function initPlayer(){startOverlay.classList.add("hidden"),idleScreen.classList.remove("hidden"),connectWebSocket()}function connectWebSocket(){const e="https:"===window.location.protocol?"wss:":"ws:",n=window.location.host,t=`${e}//${n}/ws?type=player`,o=new WebSocket(t);o.onopen=(()=>console.log("✅ STB Terhubung ke Server Karaoke")),o.onmessage=(e=>{const n=JSON.parse(e.data);console.log("📩 Perintah dari Boss:",n),"PLAY_SONG"===n.action?playSong(n.url,n.title):"PAUSE"===n.action?video.pause():"RESUME"===n.action?video.play():"STOP"===n.action?stopPlayer():"QUEUE_UPDATED"===n.action&&console.log("Antrian ada yang baru!")}),o.onclose=(()=>{console.log("❌ Koneksi terputus, mencoba reconnect..."),setTimeout(connectWebSocket,3e3)})}function playSong(e,n){idleScreen.classList.add("hidden"),video.classList.remove("hidden"),video.src=e,video.play(),currentTitle.innerText=n,nowPlaying.classList.remove("hidden"),setTimeout(()=>{nowPlaying.classList.add("hidden")},1e4)}function stopPlayer(){video.pause(),video.src="",video.classList.add("hidden"),idleScreen.classList.remove("hidden"),nowPlaying.classList.add("hidden")}const video=document.getElementById("video-player"),idleScreen=document.getElementById("idle-screen"),startOverlay=document.getElementById("start-overlay"),nowPlaying=document.getElementById("now-playing"),currentTitle=document.getElementById("current-title");let ws;video.addEventListener("ended",()=>{stopPlayer(),ws&&ws.readyState===WebSocket.OPEN&&ws.send(JSON.stringify({action:"SONG_ENDED"}))});